import java.io.FileWriter;
import java.io.IOException;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class SecureXSSExample {

    public static void main(String[] args) throws IOException {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by encoding it before outputting to the web page
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        FileWriter writer = new FileWriter("index.html");
        writer.write("<html>");
        writer.write("<head><title>XSS Example</title></head>");
        writer.write("<body>");
        writer.write("<h1>Welcome, " + encodedUserInput + "</h1>"); // Fixed code
        writer.write("</body>");
        writer.write("</html>");

        writer.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
